import{_ as a,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"36. Shift Penalty Payments","description":"","frontmatter":{"title":"36. Shift Penalty Payments","eba":"Medical Specialists 2022-2026","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/medical-specialists/wages/36-shift-penalty-payments.md","filePath":"ebas/medical-specialists/wages/36-shift-penalty-payments.md"}'),i={name:"ebas/medical-specialists/wages/36-shift-penalty-payments.md"};function r(o,e,p,l,d,c){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_36-shift-penalty-payments" tabindex="-1">36. Shift Penalty Payments <a class="header-anchor" href="#_36-shift-penalty-payments" aria-label="Permalink to &quot;36. Shift Penalty Payments&quot;">​</a></h1><p><strong>36.1</strong> For ordinary hours worked between the following times, payment will be made at the rates set out at Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> of the Agreement, plus the appropriate shift penalty payment set out in Part 3 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> which have been calculated based on the following:</p><p>Shift Percentage of applicable rate in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a></p><p>Monday to Friday, between 6.00pm and midnight 25%</p><p>Monday to Friday, between midnight and 7:00am 75% the following day</p><p>From 1 March 2023 onwards: Friday, between 50% 6.00pm and midnight</p><p>Shift Percentage of applicable rate in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a></p><p>Saturday, between 7.00am and midnight 50%</p><p>Saturday, between midnight and 7:00am (Sunday) 75%</p><p>Sunday, between 7.00am and midnight 75%</p><p>Sunday, between midnight and 7:00am (Monday) 100%</p><p><strong>36.2</strong> Friday Evening Shifts (from 1 March 2023 onwards)</p><p><strong>(a)</strong> From 1 March 2023 onwards, hours worked on Friday between 6:00pm and midnight will attract a shift penalty payment of 50% of the applicable rate in</p><p><strong>36.3</strong> The shift penalty payments under subclause 36.1 and Part 3 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> are paid in addition to the minimum rates set out at Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> of the Agreement only. Subject to <a href="/eba/ebas/medical-specialists/wages/31-remuneration-and-remuneration-increases.html">clause 31</a>, where a Doctor&#39;s actual contracted rate of pay is more than the relevant rate set out at Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> of the Agreement, the Doctor will be entitled under this Agreement to receive the contracted rate of pay, or the sum calculated in accordance with subclause 36.1, whichever is the higher.</p><p><strong>36.4</strong> The payments required by subclause 36.1 may be averaged over a period of up to 12 months as part of an annualised salary.</p><p><strong>36.5</strong> This clause does not operate so as to provide an additional financial benefit to a Doctor where a Health Service has previously agreed to provide the Doctor with a non- monetary benefit expressly in compensation for shift work and the Doctor is not worse off over all.</p><p>Plain language terms: penalty rates, shift penalty.</p>',17)])])}const f=a(i,[["render",r]]);export{m as __pageData,f as default};
